import{c as a,Q as t,j as s,g as e,n as i}from"./chunks/framework.hhGiamYR.js";const u=JSON.parse('{"title":"第18章","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/scholarship/najemy-power/18-ch18.md","filePath":"research/machiavelli/scholarship/najemy-power/18-ch18.md"}'),l={name:"research/machiavelli/scholarship/najemy-power/18-ch18.md"};function n(o,r,c,p,h,d){return t(),s("div",null,[...r[0]||(r[0]=[e("h1",{id:"第18章",tabindex:"-1"},[i("第18章 "),e("a",{class:"header-anchor",href:"#第18章","aria-label":'Permalink to "第18章"'},"​")],-1),e("p",null,"第一章 文艺复兴时期的书信 43 情，哪怕它们或许对于一位“急切的读者”(cupido lectori)而言非 常重要。彼特拉克似乎是认为，相较于原件，有些朋友对修订的版 本不会感到高兴，因为他们和他们所关心的被去掉或边缘化了。 当书信被集结起来呈现给更广大的读者时，它们便具有了不同的 目的，因此相比于写给某些特定个体，它们必须具有一种不同的 特点。 这些信的目的是什么?在给苏格拉底的信的末尾，彼特拉克 引用了西塞罗在写给他弟弟昆图斯的第一封信中的看法：“一封 书信的真正特征，是要让收信人更多了解那些他所不知的事 物”①——这种书信写作的观念或许与早先强调的让收件人的精 神与品性决定书信的性质并不一致，这当然是指出了一个不同的 方向。实际上，彼特拉克现在声称，他在书信集中所做的无非是 “说出我自己的心境或者任何其他我认为我的朋友们会感兴趣的 趣事”。简而言之，单独来看这些书信是关乎朋友们及其关切的， 统合起来看则是关于彼特拉克的。在这几句话里，我们发现他将 整个书信集视作他对自己从少年到老年的心理史和文体风格史的 一种记录或者反思。在他坦陈为老年时“人生堕入过分软弱”感 到羞愧之后，他提出“书信的编排顺序将证明”这一转变。在他少 年时他的言语( sermo) 是强健和清晰的，这“说明头脑的真正强 健”。但是，“随着时间的消逝，言语变得越来越虚弱和谦卑，也似 乎没了骨气”。他问道：“这是否说，我在少年时是一个成年男人， 而到老年反倒成了一个少年?” 这种猜测基于两个假定：第一，写作方式和言语同时反映了这 些性格和心境的变化；第二，书信集反映了他写作方式的变化。他 早先称这些书信是不一致和冲突的碎片，除了体现收件人一时一",-1),e("p",null,"① The Letters to his Brother Quintus I. 137,in the Loeb edition,tr.W.Glynn Williams, Cambridge,Mass,: Harvard University Press,1972,pp.428-429.",-1),e("p",null,"44 权力与欲望——马基雅维利与韦托里1513—1515年通信研究",-1),e("p",null,"地的需要和性质外并无特定意图和目的，而现在他又声称它们承 载着他的历史，并且几乎构成了一部他作为一个男人和一个作家 的成长过程的文献记录。但是，作为一贯套路，请注意( caveat lec- tor): 他的所有这些看法都是在一封信中[30]给出的，这封信的意 图就是向朋友们和其他读者推介一部(用他在结语部分的话说) “用多彩线条编制而成”的书信集。 这样，彼特拉克同时否定又肯定了他与友人通信的“文学创 作”性质。一方面，他说它们其实是一些文件和碎片，源自于并呈 现出他的过往，但却更多地有关收信人而非他自己。他坚称自己 的书信没有使用修辞且充满矛盾。就前者而言，虽然塞涅卡批评 了西塞罗所赞赏的书信形式(西塞罗建议阿提库斯想说什么就写 什么①),虽然彼特拉克自己为西塞罗在逆境中表现出的虚弱和软 弱感到气愤，但他仍然声称西塞罗才是他追随的典范，即便许多书 信实际上更接近塞涅卡的书信风格。另一方面，他承认他的这些 书信由于经过收集、编辑和按照特定顺序编排，已经与“最初”写 成的有所不同了。换言之，当它们被安排进某种彼此间的关系时， 它们的地位与意义已经发生了转变。因而，彼特拉克邀请他的读 者按照一本有结构和故事的书来阅读他的书信。",-1),e("p",null,"人文主义者与他们的书信集",-1),e("p",null,"科卢乔 · 萨卢塔蒂毫不怀疑彼特拉克的书信集应当跻身于其 最重要的文学成就，或者作为他修辞能力的光辉典范。在1374年 彼特拉克死后不久，萨卢塔蒂在(用书信的形式)写成的颂文中赞",-1),e("p",null,"①Letters to Atticus I.12,in vol.I of the Loeb edition,tr.E.O.Winstedt,Cambridge, Mass.:Harvard University Press,1962,pp.32-33.Seneca's criticism is in Epistulae Morales, letter 118,in vol.3 of the Loeb edition,tr.Richard M.Gummere,Cam- bridge,Mass.:Harvard University Press,1962,pp.360-361.",-1)])])}const v=a(l,[["render",n]]);export{u as __pageData,v as default};
